INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 3,
  'advanced',
  '4817 Stonegate Drive — Advanced URAR Underwriting',
  'You are appraising a home at 4817 Stonegate Drive, Greenville SC for a purchase loan underwriting assignment with Pinnacle Mortgage Partners. The contract price is $372,000. The subject is a 2,450 SF home built in 2009 with three full bathrooms, a 2-car garage, in good condition, in a standard (non-amenitied) location.

Three closed sales are provided. They differ from the subject across four adjustment types simultaneously: GLA, location (some in amenitied/gated communities), condition, and market conditions (one comp sold 11 months ago). Two of the four adjustment types have no cost method and must be supported entirely by paired sales. One of the GLA paired sales pairs is an outlier and must be addressed in your reconciliation. Your task is to identify which features differ from the subject for each comparable, derive market-supported adjustment values, apply each adjustment independently, and reconcile the adjusted prices into a value indication that supports — or refutes — the contract price.'
FROM scenario_categories WHERE code = 'M2-S4-C1';

