INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 1,
  'basic',
  '2891 Oakmont Drive — Equitable Distribution Divorce',
  'You are appraising a home at 2891 Oakmont Drive, Spartanburg SC for an equitable distribution proceeding in a divorce matter, on referral from Harrington & Cole Family Law. The subject is a 1,820 SF home built in 2001 with three bedrooms, two full bathrooms, a 2-car garage, in good condition. There is no contract price — your role is to develop an independent opinion of market value for presentation to the court.

Three closed sales are provided. Two require GLA adjustments (one larger, one smaller than the subject) and one requires a bathroom adjustment. Each adjustment must be supported by specific, identifiable market evidence — your methodology and rationale are subject to adversarial scrutiny in litigation. Identify the differing features, derive market-supported adjustment values from paired sales and cost analyses, apply them, and reconcile the adjusted prices into your independent opinion of value.'
FROM scenario_categories WHERE code = 'M2-S4-C2';

