-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 2,
  'intermediate',
  '714 Ridgewood Lane — Retrospective Estate Dispute',
  'You are appraising a home at 714 Ridgewood Lane, Greenville SC for an estate dispute and will-contest litigation matter, on referral from Thornton & Associates Estate Law. The retrospective effective date is 18 months prior to today. The subject is a 2,050 SF home built in 2004 with three bedrooms, 2.5 bathrooms, a 2-car garage, in good condition, in a similar (non-amenitied) location.

Every piece of market evidence — paired sales for GLA, location, and bathrooms, plus the resale pairs for market conditions — must reflect conditions as of the retrospective effective date. Three closed sales are provided. They differ from the subject across four adjustment types. One of the GLA paired sales pairs is divergent and requires explicit handling. Your retrospective opinion will be presented as expert testimony — opposing counsel will challenge any data that postdates the effective date. Identify the differing features, derive market-supported adjustment values, apply them, and reconcile into your retrospective opinion of value as of the prior effective date.'
FROM scenario_categories WHERE code = 'M2-S4-C2';

