ions": {"C3": "inferior"}}, {"label": "GLA", "subject": "2,050 SF", "comp_values": {"C1": "2,200 SF", "C2": "2,050 SF", "C3": "2,050 SF"}, "feature_key": "gla", "diff_comps": ["C1"], "diff_directions": {"C1": "superior"}}, {"label": "Bathrooms", "subject": "2.5", "comp_values": {"C1": "2.5", "C2": "3 full", "C3": "2.5"}, "feature_key": "bath", "diff_comps": ["C2"], "diff_directions": {"C2": "superior"}}, {"label": "Bedrooms", "subject": "3", "comp_values": {"C1": "3", "C2": "3", "C3": "3"}, "diff_comps": []}, {"label": "Garage", "subject": "2-car", "comp_values": {"C1": "2-car", "C2": "2-car", "C3": "2-car"}, "diff_comps": []}, {"label": "Year Built", "subject": "2004", "comp_values": {"C1": "2005", "C2": "2004", "C3": "2003"}, "diff_comps": []}, {"label": "Condition", "subject": "Good", "comp_values": {"C1": "Good", "C2": "Good", "C3": "Good"}, "diff_comps": []}, {"label": "Location", "subject": "Similar", "comp_values": {"C1": "Amenitied", "C2": "Similar", "C3": "Similar"}, "feature_key": "loc", "diff_comps": ["C1"], "diff_directions": {"C1": "superior"}}], "step2": {"tabs": [{"key": "paired", "label": "Paired Sales Analysis", "intro": "Use the supporting market data — all confirmed from the retrospective market period — to derive contributory values. Four tables: GLA, location, bathrooms, and market conditions. Note that GLA Pair 3 diverges from Pairs 1 & 2.", "tables": [{"kind": "paired_dollar_per_unit", "feature_key": "gla", "title": "GLA Pairs — Calculate $/SF (Retrospective Data)", "instruction": "Each pair confirmed equivalent except GLA, all from the retrospective market period. Pair 3 produces $57.33/SF — well above Pairs 1 & 2 at $48–$50/SF. In a retrospective litigation context, this divergence must be explained explicitly in your reconciliation.", "input_label": "Your $/SF", "input_suffix": "/SF", "rows": [{"label": "1", "cells": ["1,950 SF / $296,000", "2,100 SF / $303,200", "150 SF", "$7,200"]}, {"label": "2", "cells": ["2,000 SF / $302,500", "2,150 SF / $310,000", "150 SF", "$7,500"]}, {"label": "3", "cells": ["2,050 SF / $308,000", "2,200 SF / $316,600", "150 SF", "$8,600"]}], "column_headers": ["Pair", "Sale A (SF / Price)", "Sale B (SF / Price)", "SF Diff", "Price Diff"], "concluded_label": "Concluded GLA Adjustment", "concluded_helper": "Bracket toward Pairs 1 & 2; address Pair 3''s divergence explicitly."}, {"kind": "paired_dollar_diff", "feature_key": "loc", "title": "Location Pairs — Similar vs. Amenitied (Retrospective)", "instruction": "All pairs confirmed from retrospective market period. No cost method available. Calculate price difference (Amenitied minus Similar/Standard).", "input_label": "Your Price Difference", "input_suffix": "", "rows": [{"label": "1", "cells": ["$298,000", "$312,000"]}, {"label": "2", "cells": ["$305,000", "$319,500"]}, {"label": "3", "cells": ["$301,000", "$316,000"]}], "column_headers": ["Pair", "Similar Sale", "Amenitied Sale"], "concluded_label": "Concluded Location Adjustment", "concluded_helper": "Pairs cluster tightly — strong retrospective market support."}, {"kind": "paired_dollar_diff", "feature_key": "bath", "title": "Bathroom Pairs — 2.5 vs. 3 Full Baths (Retrospective)", "instruction": "Pairs isolate the bathroom count difference. All pairs confirmed from retrospective market period. Subtract the 2.5-bath sale price from the 3-full-bath sale price.", "input_label": "Your Price Difference", "input_suffix": "", "rows": [{"label": "1", "cells": ["$300,500", "$307,200"]}, {"label": "2", "cells": ["$296,000", "$302,900"]}], "column_headers": ["Pair", "2.5 Bath Sale", "3 Full Bath Sale"], "concluded_label": "Concluded Bathroom Adjustment", "concluded_helper": "Bracket your two results."}, {"kind": "paired_pct_per_month", "feature_key": "date", "title": "Market Conditions — Retrospective Resale Pair Analysis", "instruction": "The same properties sold twice during the retrospective market period. For each pair, calculate the monthly appreciation rate using: (Resale − Original) ÷ Original ÷ Months × 100", "input_label": "Your %/Month", "input_suffix": "%/mo", "rows": [{"label": "A", "cells": ["$291,000", "$299,546", "9"]}, {"label": "B", "cells": ["$304,000", "$312,512", "11"]}, {"label": "C", "cells": ["$298,000", "$307,040", "10"]}], "column_headers": ["Property", "Original Sale Price", "Resale Price", "Months"], "concluded_label": "Concluded Monthly Rate", "concluded_helper": "Bracket your three results — note the wider spread."}]}, {"key": "cost", "label": "Cost-Based Support", "intro": "Calculate the depreciated contributory value for GLA and Bathrooms using retrospective cost data. No cost method is applicable for location or market conditions adjustments.", "items": [{"kind": "cost_calc", "feature_key": "gla", "title": "GLA Contributory Value ($/SF) — Retrospective", "fact_rows": [["RCN (retrospective)", "$77.00 / SF"], ["Effective Age", "20 years"], ["Economic Life", "60 years"], ["Depreciation Rate", "20 ÷ 60 = 33.3%"], ["Formula", "$77.00 × (1 − 0.333) = ?"]], "input_suffix": "/SF"}, {"kind": "cost_calc", "feature_key": "bath", "title": "Bathroom Cost (Full Bath Addition) — Retrospective", "fact_rows": [["Cost (retrospective)", "$13,500"], ["Effective Age", "20 years"], ["Economic Life", "60 years"], ["Depreciation Rate", "33.3%"], ["Formula", "$13,500 × (1 − 0.333) = ?"]], "input_suffix": ""}]}], "reconciliation": {"instruction": "Review both method indications and enter your reconciled adjustment for each item. All values must reflect conditions as of the retrospective effective date. Cost is available for GLA and bathrooms only.", "items": [{"feature_key": "gla", "label": "GLA Adjustment ($/SF)"}, {"feature_key": "loc", "label": "Location Adjustment ($)"}, {"feature_key": "bath", "label": "Bathroom Adjustment ($)"}, {"feature_key": "date", "label": "Market Conditions Adjustment (%/mo)"}]}}, "step3": {"instruction": "Apply your reconciled adjustments to each comparable. All adjustments reflect retrospective effective date conditions. Use a NEGATIVE value where the comp is superior to the subject, and a POSITIVE value where it is inferior. For Comp 3 (market conditions), calculate as: $289,000 × 8 months × your reconciled %/mo ÷ 100. Document each rationale carefully — opposing counsel will specifically challenge the temporal validity of your supporting evidence.", "applicable": {"C1": ["gla", "loc"], "C2": ["bath"], "C3": ["date"]}, "method_dropdown": ["Paired Sales Analysis", "Location Paired Sales Analysis", "Market Conditions (Resale Pairs)", "Cost-Based Support", "Grouped Paired Sales", "Regression Analysis", "Appraiser Judgment / Extraction"], "support_min_chars": 15}, "step4": {"show_net_gross_panel": false}}'::jsonb,
  '{"step1_correct_flags": {"C1": ["gla", "loc"], "C2": ["bath"], "C3": ["date"]}, "step1_rationale": "Comp 1 is 150 SF larger (superior GLA) and in an amenitied location (superior) — two adjustments. Comp 2 has 3 full baths versus the subject''s 2.5 (superior bath, single adjustment). Comp 3 sold 8 months prior to the retrospective effective date (older in an appreciating market — inferior date, single adjustment). All other features (bedrooms, garage, year built, condition) are equivalent. All adjustments reflect retrospective effective date conditions.", "step2_tables": {"paired": {"gla": {"pair_answers": [48.0, 50.0, 57.33], "concluded_range": [48.0, 51.0], "rationale": "Pairs 1 and 2 cluster tightly at $48 and $50/SF — consistent retrospective market evidence. Pair 3 diverges to $57.33/SF and must be addressed in litigation: possible different submarket, anomalous transaction, or data anomaly. Bracket conclusion toward Pairs 1 & 2."}, "loc": {"pair_answers": [14000, 14500, 15000], "concluded_range": [14000, 15000], "rationale": "Three pairs produce $14,000–$15,000 — tight retrospective support for the location premium. No cost method applicable."}, "bath": {"pair_answers": [6700, 6900], "concluded_range": [6700, 6900], "rationale": "Two pairs bracket the half-bath increment at $6,700 and $6,900 — tight retrospective support."}, "date": {"pair_answers": [0.326, 0.254, 0.303], "concluded_range": [0.28, 0.32], "rationale": "Three resale pairs produce 0.25%, 0.30%, and 0.33%/mo — a wider spread than typically seen. Bracket the consistent values (0.30%, 0.33%) and address the lower outlier (0.25%) in your rationale. The wider spread requires careful bracketing rather than mechanical averaging."}}, "cost": {"gla": {"answer": 51.36, "rationale": "$77.00 × (1 − 0.333) = $51.36/SF — retrospective cost. Falls near the top of the consistent paired sales range ($48–$50/SF), providing convergent support with mild ceiling characteristics."}, "bath": {"answer": 9005, "rationale": "$13,500 × (1 − 0.333) = $9,005 — retrospective cost. Significantly exceeds paired sales of $6,700–$6,900. Cost is a ceiling only; weight paired sales."}}}, "step2_reconciliation": {"gla": {"range": [48.0, 51.0], "rationale": "Paired sales support $48–$50/SF (Pairs 1 & 2). Pair 3''s $57.33/SF is excluded with documented retrospective reasoning. Cost support of $51.36/SF is a credible mild ceiling. Reconcile in the $49–$50/SF range, weighting paired sales heavily."}, "loc": {"range": [14000, 15000], "rationale": "Three retrospective paired sales support $14,000–$15,000. No cost method applicable. Reconcile near the midpoint at approximately $14,500."}, "bath": {"range": [6700, 6900], "rationale": "Paired sales bracket $6,700–$6,900 in retrospective data. Cost of $9,005 is significantly higher and serves only as a ceiling. Reconcile within the paired bracket near $6,800."}, "date": {"range": [0.28, 0.32], "rationale": "Paired sales support 0.28–0.32%/mo, bracketing the consistent values from Pairs A and C. Pair B''s 0.25% is an outlier in retrospective data. No cost method applicable. Reconcile near the midpoint at approximately 0.30%/mo."}}, "step3_adjustments": {"C1": {"gla": {"direction": "negative", "amount_per_unit": -49.5, "units": 150, "computed_amount": -7425, "method": "Paired Sales Analysis", "rationale": "Comp 1 is 150 SF larger than the subject (superior). At a reconciled rate of approximately $49.50/SF (drawn from retrospective Pairs 1 & 2), the GLA adjustment is approximately −$7,425. Round to nearest $50."}, "loc": {"direction": "negative", "amount": -14500, "method": "Location Paired Sales Analysis", "rationale": "Comp 1 is in an amenitied location (superior to the subject''s similar/standard). The location premium derived from three retrospective pairs is approximately $14,500."}}, "C2": {"bath": {"direction": "negative", "amount": -6800, "method": "Paired Sales Analysis", "rationale": "Comp 2 has 3 full baths versus the subject''s 2.5 (superior). The half-bath increment from retrospective paired sales is approximately $6,800."}}, "C3": {"date": {"direction": "positive", "amount": 6936, "method": "Market Conditions (Resale Pairs)", "rationale": "Comp 3 sold 8 months prior to the retrospective effective date (inferior date in an appreciating market). At a reconciled rate of 0.30%/mo: $289,000 × 8 × 0.30 ÷ 100 = $6,936."}}}, "step4_adjusted_prices": {"C1": {"unadjusted": 312000, "adjusted": 290075}, "C2": {"unadjusted": 308500, "adjusted": 301700}, "C3": {"unadjusted": 289000, "adjusted": 295936}}, "step4_reconciliation_narrative": "Adjusted prices range from approximately $290,075 to $301,700 as of the retrospective effective date — a spread of approximately $11,625. The retrospective opinion of value is supported in the $293,000–$298,000 range, with Comp 2 (single small bathroom adjustment) deserving the most weight. The standard-level teaching points are: (1) the GLA Pair 3 outlier ($57.33/SF) must be excluded with documented retrospective reasoning rather than averaged, (2) the wider market conditions spread (0.25%–0.33%/mo) requires careful bracketing, and (3) every supporting data point must reflect conditions as of the retrospective effective date — opposing counsel will challenge any data that postdates it. The opinion is presented as expert testimony in the estate dispute proceeding.", "tolerance_note": "Student answers are accepted within ±5% of model derived values for paired-sales calculations and within the indicated reconciliation range. Step 3 adjustments accepted within ±13% of the computed amount for GLA, ±12% for location and bath, and ±16% for market conditions."}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'adjustment_grid'
WHERE sc.code = 'M2-S4-C2'
  AND s.order_index = 2;

