-- Scenario: 3340 Crestwood Circle — Partition Action with Functional Obsolescence
-- Category M2-S4-C2 #3 · difficulty 'advanced'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 3,
  'advanced',
  '3340 Crestwood Circle — Partition Action with Functional Obsolescence',
  'You are appraising a home at 3340 Crestwood Circle, Anderson SC for a partition action and co-ownership dispute, on referral from Bowers, Finch & Hale Litigation Group. The subject is a 2,300 SF home built in 2000 with 2.5 bathrooms, a 2-car garage, in good condition, in a standard location, with adequate functional layout.

Three closed sales are provided. They differ from the subject across six adjustment types: GLA, garage size, location, condition, market conditions, and functional obsolescence (Comp 3 has a non-conforming layout). Each adjustment must meet the Daubert standard — peer-accepted methodology, reproducible analysis, supported by specific market evidence. The GLA paired sales include an outlier that must be excluded with documented reasoning. Comp 3 carries three simultaneous upward adjustments — its gross adjustment will be substantial, requiring explicit weighting commentary in your reconciliation. Identify the differing features, derive market-supported adjustments, apply them independently, and reconcile into your independent opinion of value for the partition proceeding.'
FROM scenario_categories WHERE code = 'M2-S4-C2';

